create table public.rater_assignments (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  cycle_id uuid not null references public.assessment_cycles(id) on delete cascade,  evaluated_cycle_participant_id uuid not null references public.cycle_participants(id) on delete cascade,  evaluator_cycle_participant_id uuid not null references public.cycle_participants(id),  relationship_code text not null references public.relationship_types(code),  questionnaire_id uuid references public.questionnaires(id),  magic_token_hash text unique,  token_expires_at timestamptz,  status text not null default 'pending'    check (status in ('pending','invited','completed','expired','cancelled')),  invited_at timestamptz,  completed_at timestamptz,  used_at timestamptz,  created_at timestamptz not null default now(),  unique (cycle_id, evaluated_cycle_participant_id, evaluator_cycle_participant_id, relationship_code));create index on public.rater_assignments (tenant_id, cycle_id, status);create index on public.rater_assignments (evaluated_cycle_participant_id);create table public.responses (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  assignment_id uuid not null references public.rater_assignments(id) on delete cascade,  question_id uuid not null references public.questions(id),  score numeric,  text_answer text,  question_snapshot_json jsonb,  created_at timestamptz not null default now(),  unique (assignment_id, question_id));create index on public.responses (tenant_id, assignment_id);